// 메이크샵 상품 목록 파싱 + 키워드 자동 추출
var raw = $input.first().json;
var body = typeof raw === 'string' ? raw : (raw.body || JSON.stringify(raw));

// JSON 파싱 시도
var data;
try { data = JSON.parse(body); } catch(e) { data = raw; }

// return_code 확인
if (data && data.return_code && data.return_code !== '0000') {
  throw new Error('Makeshop API error: ' + data.return_code + ' / ' + JSON.stringify(data));
}

// 상품 목록 추출
var products = [];
if (data && data.datas && Array.isArray(data.datas)) {
  products = data.datas;
} else if (data && Array.isArray(data)) {
  products = data;
}

// 카테고리 키워드 매핑
var CATEGORY_KEYWORDS = {
  '압화': ['압화', '프레스드플라워', '프레스드', '건조꽃', '드라이플라워'],
  '레진': ['레진', 'UV레진', '에폭시', '실리콘몰드', '몰드'],
  '캔들': ['캔들', '왁스', '소이왁스', '향초', '심지', '캔들틴'],
  '석고': ['석고', '방향제', '석고방향제', '아로마'],
  '비즈': ['비즈', '구슬', '실', '바늘', '클레이']
};

function extractKeywords(name) {
  if (!name) return [];
  var kws = [];
  var lname = name.toLowerCase();
  for (var cat in CATEGORY_KEYWORDS) {
    var words = CATEGORY_KEYWORDS[cat];
    for (var i = 0; i < words.length; i++) {
      if (lname.indexOf(words[i]) >= 0) {
        if (kws.indexOf(words[i]) < 0) kws.push(words[i]);
      }
    }
  }
  return kws;
}

function detectCategory(name) {
  if (!name) return '';
  var lname = name.toLowerCase();
  for (var cat in CATEGORY_KEYWORDS) {
    var words = CATEGORY_KEYWORDS[cat];
    for (var i = 0; i < words.length; i++) {
      if (lname.indexOf(words[i]) >= 0) return cat;
    }
  }
  return '';
}

var records = [];
for (var j = 0; j < products.length; j++) {
  var p = products[j];
  var branduid = String(p.branduid || p.uid || p.product_id || '');
  var name = p.product_name || p.name || '';
  var price = parseInt(p.sellprice || p.price || 0);
  var image = p.image1 || p.image || '';
  var catCode = p.cate1 || p.category_code || '';
  var keywords = extractKeywords(name);
  var catName = detectCategory(name);

  if (branduid && name) {
    records.push({
      branduid: branduid,
      product_name: name,
      price: price,
      image_url: image,
      product_url: '/shop/shopdetail.html?branduid=' + branduid,
      category_code: catCode,
      category_name: catName,
      keywords: JSON.stringify(keywords),
      status: 'active',
      synced_at: new Date().toISOString()
    });
  }
}

return [{ json: { products: records, total: records.length } }];

// 신규/변경 상품 NocoDB Upsert
var parsed = $('Parse Products').first().json;
var existingResp = $input.first().json;

var newProducts = parsed.products || [];
var existing = (existingResp && existingResp.list) ? existingResp.list : [];

// 기존 branduid → Id 맵
var existingMap = {};
for (var i = 0; i < existing.length; i++) {
  existingMap[String(existing[i].branduid)] = existing[i].Id;
}

var toInsert = [];
var toUpdate = [];

for (var j = 0; j < newProducts.length; j++) {
  var p = newProducts[j];
  if (existingMap[p.branduid]) {
    toUpdate.push({ id: existingMap[p.branduid], data: p });
  } else {
    toInsert.push(p);
  }
}

return [{ json: { toInsert, toUpdate, insertCount: toInsert.length, updateCount: toUpdate.length } }];

var upsertData = $('Upsert Products').first().json;
var insertResult = $('Bulk Insert New Products').first().json;
var insertCount = upsertData.insertCount || 0;
var updateCount = upsertData.updateCount || 0;
var msg = '📦 메이크샵 상품 카탁로그 동기화 완료
신규: ' + insertCount + '개
기존 업데이트: ' + updateCount + '개
시간: ' + new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });
return [{ json: { message: msg, insertCount, updateCount } }];
